var e=[{id:`L2_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`결국 본색을 드러내시는군요. 서로에 대해 더욱 깊이 알게 되었으니, 저희 협력 관계가 예전보다 돈독해졌다고 해야겠죠. 오히려 사장님에 대해 흥미가 생겼어요.`,JPN:`結局本性を現しましたわね。お互いにより深く知ることができましたので、私たちの協力関係も以前より深くなったと言えます。むしろ……あなたに対して興味が湧いてきましたわ。`,ENG:`Finally, you showed me your true intentions. Now that we know more about each other, our collaborative relationship is stronger than ever. This also has made me curious about you.`,TWN:`你終於露出本性了呢。我們對彼此都有了更深入的瞭解，那麼雙方的合作關係應該會比以往更加深厚。我反而對老闆產生了興趣呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`후훗, 물론 정중한 방법으로 표현할 테니 염려는 마세요.`,JPN:`ふふっ、もちろん丁重におもてなしするのでご心配なく。`,ENG:`Hah hah. Don't worry. I'm not going to openly express my interest in you.`,TWN:`呵呵，當然，我會用禮貌的方法來表達，請不用擔心。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};